-- ============================================================
-- DLM_TESTDATA_INIT : 테스트데이터 자동생성 JOB 초기 데이터
-- ============================================================
-- 운영 데이터를 마스터키맵으로 비식별 변환하여 검증/개발계로 이관하는
-- 테스트데이터 자동생성(TDM) JOB 정의를 일괄 등록하는 초기 스크립트입니다.
--
-- [등록 JOB]
--   TESTDATA_AUTO_GEN        : 테스트데이터 자동생성(전체)
--   TESTDATA_AUTO_GEN_FIXED  : 테스트데이터 자동생성(전체)_FIXED
--   ※ 두 JOB 모두 VERSION 1 만 적재 (최신 운영 export 기준 — 2026-04-25)
--
-- [STEP 구성]
--   GEN_KEYMAP            : 신청 고객번호 연관 키맵 추출
--   MIG_KEYMAP            : KEYMAP 을 검증/개발계 DB 로 이관
--   GEN_MASTER_KEYMAP     : 검증/개발계의 MASTER KEY 생성
--   EXE_TRANSFORM         : 개인정보변환 + MASTERKEY 매핑 (SCRAMBLE)
--   BROADCAST_MASTERKEY   : TARGET MASTERKEYMAP 전달
--   EXE_FINISH            : JOB 마무리
--
-- [등록 테이블]
--   1. TBL_PIIJOB        : JOB 헤더
--   2. TBL_PIISTEP       : JOB 별 STEP 정의
--   3. TBL_PIISTEPTABLE  : STEP 별 처리 테이블 / 변환 SQL
--
-- ============================================================
-- 사이트별 배포 시 아래 변수를 해당 사이트 값으로 치환(Replace All)하세요.
--
--   COTDL       -> DLM 스키마명         (기본값: COTDL)
--   DAON        -> 운영 원천 DB 명      (예: DAON)
--   DAOND       -> 검증/개발계 DB 명    (예: DAOND)
--   COOWNSER    -> 원천 OWNER (계약)    (예: COOWNSER)
--   #KEYMAP_ID  -> 런타임 치환 (KEYMAP_ID)
--   #BASEDATE   -> 런타임 치환 (BASEDATE)
--   #ORDERID    -> 런타임 치환 (ORDERID)
-- ============================================================


-- ────────────────────────────────────────────────────────────
-- 기존 데이터 삭제 (JOBID 스코프 — 다른 JOB 영향 없음)
-- 자식 테이블 → 부모 테이블 순서로 삭제
-- ────────────────────────────────────────────────────────────
DELETE FROM COTDL.TBL_PIISTEPTABLE WHERE JOBID IN ('TESTDATA_AUTO_GEN','TESTDATA_AUTO_GEN_FIXED');
DELETE FROM COTDL.TBL_PIISTEP      WHERE JOBID IN ('TESTDATA_AUTO_GEN','TESTDATA_AUTO_GEN_FIXED');
DELETE FROM COTDL.TBL_PIIJOB       WHERE JOBID IN ('TESTDATA_AUTO_GEN','TESTDATA_AUTO_GEN_FIXED');


