SELECT 
#ORDERID,
DB,
SUBSTR(KEY_NAME, 5),
BASEDATE, CUSTID,
VAL1,
#CURVAL+rownum
from 
COTDL.TBL_PIIKEYMAP
WHERE KEY_NAME = ''KEY_ACTID'' and KEYMAP_ID = ''#KEYMAP_ID''
 /*
  ##### CURVAL #####
  SELECT RPRS_SRNO FROM COOWNSER.TCMSRNINFOQ WHERE SRNO_SVCD = ''CM05001''
  ;
  ##### UPDATE #####
  UPDATE COOWNSER.TCMSRNINFOQ
      SET RPRS_SRNO = RPRS_SRNO + (SELECT COUNT(1)
                     FROM COTDL.TBL_PIIKEYMAP
                     WHERE KEY_NAME = ''KEY_ACTID'' and KEYMAP_ID = ''#KEYMAP_ID'' 
                    )
      WHERE SRNO_SVCD = ''CM05001''
  */
',NULL,NULL,NULL,'',NULL,'2026-04-25 12:26:46','2026-04-25 12:26:46','admin','admin',NULL,NULL,NULL,NULL,NULL,NULL,NULL),
